import { useState } from "react";
import JoiningDetails from "./components/JoiningDetails";
import PersonalDetails from "./components/PersonalDetails";
import FamilyDetails from "./components/FamilyDetails";
import Academic from "./components/Academic";
import WorkHistory from "./components/WorkHistory";
import Nominees from "./components/Nominees";
import Consents from "./components/Consents";
function App() {
 const [step, setStep] = useState(1);
 const [formData, setFormData] = useState({});
 const nextStep = () => setStep(step + 1);
 const prevStep = () => setStep(step - 1);
 const updateData = (data) => {
   setFormData({ ...formData, ...data });
 };
 switch (step) {
   case 1:
     return <JoiningDetails nextStep={nextStep} updateData={updateData} />;
   case 2:
     return <PersonalDetails nextStep={nextStep} prevStep={prevStep} updateData={updateData} />;
   case 3:
     return <FamilyDetails nextStep={nextStep} prevStep={prevStep} updateData={updateData} />;
   case 4:
     return <Academic nextStep={nextStep} prevStep={prevStep} updateData={updateData} />;
   case 5:
     return <WorkHistory nextStep={nextStep} prevStep={prevStep} updateData={updateData} />;
   case 6:
     return <Nominees nextStep={nextStep} prevStep={prevStep} updateData={updateData} />;
   case 7:
     return <Consents prevStep={prevStep} formData={formData} />;
   default:
     return <h1>Completed</h1>;
 }
}
export default App;
